CREATE INDEX idx_views_count ON views (count);
CREATE TRIGGER tgr_views_raise_on_created_update BEFORE UPDATE OF created ON views BEGIN SELECT RAISE(FAIL, 'Cannot update created column') WHERE OLD.created != NEW.created; END;
